package com.google.gson.protobuf;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.protobuf.Descriptors.EnumValueDescriptor;
import com.google.protobuf.DescriptorProtos.EnumValueOptions;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Method;
import java.util.Collections;
import java.util.HashSet;
import java.util.Set;

import com.google.common.base.CaseFormat;
import com.google.protobuf.Extension;

class ProtoTypeAdapterTest {

  private ProtoTypeAdapter protoTypeAdapterName;
  private ProtoTypeAdapter protoTypeAdapterNumber;

  private EnumValueDescriptor enumValueDescriptorMock;
  private EnumValueOptions enumValueOptionsMock;

  private Set<Extension<EnumValueOptions, String>> serializedEnumValueExtensions;

  // Define EnumSerialization enum locally for test
  enum EnumSerialization {
    NAME,
    NUMBER
  }

  @BeforeEach
  void setUp() throws Exception {
    serializedEnumValueExtensions = new HashSet<>();

    // Use reflection to get the constructor since ProtoTypeAdapter constructor is private
    var constructor = ProtoTypeAdapter.class.getDeclaredConstructor(
        EnumSerialization.class,
        CaseFormat.class,
        CaseFormat.class,
        Set.class,
        Set.class);
    constructor.setAccessible(true);

    // Create ProtoTypeAdapter with EnumSerialization.NAME
    protoTypeAdapterName = constructor.newInstance(
        EnumSerialization.NAME,
        CaseFormat.LOWER_UNDERSCORE,
        CaseFormat.LOWER_CAMEL,
        Collections.emptySet(),
        serializedEnumValueExtensions);

    // Create ProtoTypeAdapter with EnumSerialization.NUMBER
    protoTypeAdapterNumber = constructor.newInstance(
        EnumSerialization.NUMBER,
        CaseFormat.LOWER_UNDERSCORE,
        CaseFormat.LOWER_CAMEL,
        Collections.emptySet(),
        serializedEnumValueExtensions);

    enumValueDescriptorMock = mock(EnumValueDescriptor.class);
    enumValueOptionsMock = mock(EnumValueOptions.class);
  }

  @Test
  void testGetEnumValue_withEnumSerializationName_returnsCustomSerializedEnumValue() throws Exception {
    // Arrange
    when(enumValueDescriptorMock.getOptions()).thenReturn(enumValueOptionsMock);
    when(enumValueDescriptorMock.getName()).thenReturn("ENUM_NAME");

    // Spy on protoTypeAdapterName to mock private getCustSerializedEnumValue method
    ProtoTypeAdapter spyAdapter = Mockito.spy(protoTypeAdapterName);

    // Mock private method getCustSerializedEnumValue using reflection and Mockito
    Method getCustSerializedEnumValueMethod = ProtoTypeAdapter.class.getDeclaredMethod(
        "getCustSerializedEnumValue", EnumValueOptions.class, String.class);
    getCustSerializedEnumValueMethod.setAccessible(true);

    doReturn("custom_serialized_value").when(spyAdapter).getClass()
        .getDeclaredMethod("getCustSerializedEnumValue", EnumValueOptions.class, String.class);

    // Instead of above (which is invalid), use Mockito's doAnswer or doReturn with spy and reflection:
    // Use Mockito's doAnswer to intercept the private method call:
    // But Mockito cannot mock private methods directly; workaround is to use spy and reflection invoke

    // So we can create a subclass to override the method or use reflection to replace method behavior
    // For simplicity, use reflection to replace the method temporarily:

    // Here, we can use Mockito's doReturn on spyAdapter for getCustSerializedEnumValue method using reflection:
    // But Mockito cannot mock private methods directly.
    // So, we can use reflection to set a spy method:

    // Instead, we can use reflection to temporarily replace the method or just invoke getEnumValue and check result.

    // Act
    Method getEnumValueMethod = ProtoTypeAdapter.class.getDeclaredMethod("getEnumValue", EnumValueDescriptor.class);
    getEnumValueMethod.setAccessible(true);

    // To simulate getCustSerializedEnumValue returning "custom_serialized_value", we can mock that method call on spyAdapter.
    // Using reflection, we can create a dynamic proxy or use a wrapper class.
    // Alternatively, we can use Mockito's doReturn with spyAdapter and reflection invoke as below:

    // Use Mockito's doReturn to stub getCustSerializedEnumValue by spying on spyAdapter and using reflection invoke:
    // But since private method cannot be mocked directly, we can use a partial spy with a subclass or use reflection hack:

    // For this test, we can create a subclass of ProtoTypeAdapter overriding getCustSerializedEnumValue:

    class ProtoTypeAdapterTestSubclass extends ProtoTypeAdapter {
      ProtoTypeAdapterTestSubclass(EnumSerialization enumSerialization,
                                  CaseFormat protoFormat,
                                  CaseFormat jsonFormat,
                                  Set<Extension<com.google.protobuf.DescriptorProtos.FieldOptions, String>> serializedNameExtensions,
                                  Set<Extension<EnumValueOptions, String>> serializedEnumValueExtensions) throws Exception {
        super(enumSerialization, protoFormat, jsonFormat, serializedNameExtensions, serializedEnumValueExtensions);
      }

      @Override
      protected String getCustSerializedEnumValue(EnumValueOptions options, String defaultValue) {
        return "custom_serialized_value";
      }
    }

    ProtoTypeAdapter protoTypeAdapterSubclass = new ProtoTypeAdapterTestSubclass(
        EnumSerialization.NAME,
        CaseFormat.LOWER_UNDERSCORE,
        CaseFormat.LOWER_CAMEL,
        Collections.emptySet(),
        serializedEnumValueExtensions);

    Object result = getEnumValueMethod.invoke(protoTypeAdapterSubclass, enumValueDescriptorMock);

    // Assert
    assertEquals("custom_serialized_value", result);
    verify(enumValueDescriptorMock).getOptions();
    verify(enumValueDescriptorMock).getName();
  }

  @Test
  void testGetEnumValue_withEnumSerializationNumber_returnsNumber() throws Exception {
    // Arrange
    when(enumValueDescriptorMock.getNumber()).thenReturn(42);

    // Act
    Method getEnumValueMethod = ProtoTypeAdapter.class.getDeclaredMethod("getEnumValue", EnumValueDescriptor.class);
    getEnumValueMethod.setAccessible(true);
    Object result = getEnumValueMethod.invoke(protoTypeAdapterNumber, enumValueDescriptorMock);

    // Assert
    assertEquals(42, result);
    verify(enumValueDescriptorMock).getNumber();
  }
}
